import { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';

// Equirectangular world map (actual country borders), rendered black & white.
// Black = ocean / background, white = land, hairline borders = countries.
const WORLD_MAP_DATA_URL = "data:image/png;base64,";

const GLOBE_RADIUS = 2.2;

function buildStarfield(count = 700, radius = 40) {
  const positions = [];
  for (let i = 0; i < count; i++) {
    const u = Math.random();
    const v = Math.random();
    const theta = 2 * Math.PI * u;
    const phi = Math.acos(2 * v - 1);
    const r = radius * (0.6 + Math.random() * 0.4);
    positions.push(
      r * Math.sin(phi) * Math.cos(theta),
      r * Math.sin(phi) * Math.sin(theta),
      r * Math.cos(phi)
    );
  }
  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  return geometry;
}

export function Globe() {
  const containerRef = useRef(null);
  const [webGlSupported, setWebGlSupported] = useState(true);
  const [, setReady] = useState(false);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    let scene, camera, renderer;
    let globeGeo, globeMat, texture, globeMesh, globeGroup;
    let starMat, starGeo, stars;
    let stemGeo, stemMat, headGeo, headMat, ringGeo, ringMat;
    let frameId;
    let autoRotate = true;
    let dragging = false;
    let prevX = 0, prevY = 0;
    let idleTimeout;
    let resizeObserver;

    const onPointerDown = (e) => {
      dragging = true;
      autoRotate = false;
      prevX = e.clientX; prevY = e.clientY;
      if (idleTimeout) clearTimeout(idleTimeout);
      if (renderer && renderer.domElement) {
        renderer.domElement.style.cursor = 'grabbing';
      }
    };

    const onPointerMove = (e) => {
      if (!dragging || !globeGroup) return;
      const dx = e.clientX - prevX;
      const dy = e.clientY - prevY;
      globeGroup.rotation.y += dx * 0.005;
      globeGroup.rotation.x += dy * 0.005;
      globeGroup.rotation.x = Math.max(-1.1, Math.min(1.1, globeGroup.rotation.x));
      prevX = e.clientX; prevY = e.clientY;
    };

    const onPointerUp = () => {
      dragging = false;
      if (renderer && renderer.domElement) {
        renderer.domElement.style.cursor = 'grab';
      }
      idleTimeout = setTimeout(() => { autoRotate = true; }, 1500);
    };

    const activeRings = [];
    let spinBoost = 0;
    let handlePulse;

    try {
      // Check if WebGL is supported
      const canvas = document.createElement('canvas');
      const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
      if (!gl) {
        throw new Error('WebGL context not available');
      }

      scene = new THREE.Scene();
      camera = new THREE.PerspectiveCamera(45, 1, 0.1, 100);
      camera.position.set(0, 0, 6.5);

      renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
      renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
      container.appendChild(renderer.domElement);

      // Solid globe textured with real country shapes
      texture = new THREE.TextureLoader().setCrossOrigin('').load(WORLD_MAP_DATA_URL, () => setReady(true));
      texture.minFilter = THREE.LinearFilter;
      texture.magFilter = THREE.LinearFilter;

      globeGeo = new THREE.SphereGeometry(GLOBE_RADIUS, 96, 64);
      globeMat = new THREE.MeshBasicMaterial({ map: texture });
      globeMesh = new THREE.Mesh(globeGeo, globeMat);

      globeGroup = new THREE.Group();
      globeGroup.add(globeMesh);
      globeGroup.rotation.x = 0.15;
      scene.add(globeGroup);

      // Create 3D pin on India
      stemGeo = new THREE.CylinderGeometry(0.018, 0.018, 0.35, 8);
      headGeo = new THREE.SphereGeometry(0.07, 16, 16);
      ringGeo = new THREE.RingGeometry(0.02, 0.16, 32);

      const addPin = (pinLat, pinLng, colorHex) => {
        const phi = pinLat * (Math.PI / 180);
        const theta = Math.PI + pinLng * (Math.PI / 180);
        
        const x = -GLOBE_RADIUS * Math.cos(phi) * Math.cos(theta);
        const y = GLOBE_RADIUS * Math.sin(phi);
        const z = GLOBE_RADIUS * Math.cos(phi) * Math.sin(theta);
        const pinPos = new THREE.Vector3(x, y, z);
        
        const pinGroup = new THREE.Group();
        const mat = new THREE.MeshBasicMaterial({ color: colorHex });
        
        // Create unique material per ring so they can fade independently
        const rMat = new THREE.MeshBasicMaterial({ 
          color: colorHex, 
          side: THREE.DoubleSide, 
          transparent: true, 
          opacity: 0.6 
        });

        const stem = new THREE.Mesh(stemGeo, mat);
        stem.position.y = 0.175;
        pinGroup.add(stem);

        const head = new THREE.Mesh(headGeo, mat);
        head.position.y = 0.35;
        pinGroup.add(head);

        const ring = new THREE.Mesh(ringGeo, rMat);
        ring.rotation.x = Math.PI / 2;
        pinGroup.add(ring);

        pinGroup.position.copy(pinPos);
        
        const upVector = new THREE.Vector3(0, 1, 0);
        const targetVector = pinPos.clone().normalize();
        pinGroup.quaternion.setFromUnitVectors(upVector, targetVector);
        
        globeGroup.add(pinGroup);
        activeRings.push(ring);
      };

      addPin(22.0, 77.0, 0xff0000); // India - Red (matching the red theme)

      // Static distant starfield for depth
      starMat = new THREE.PointsMaterial({ color: 0xffffff, size: 0.03, transparent: true, opacity: 0.5 });
      starGeo = buildStarfield();
      stars = new THREE.Points(starGeo, starMat);
      scene.add(stars);

      const resize = () => {
        const { clientWidth, clientHeight } = container;
        if (!clientWidth || !clientHeight) return;
        camera.aspect = clientWidth / clientHeight;
        camera.updateProjectionMatrix();
        renderer.setSize(clientWidth, clientHeight);
      };
      resize();
      resizeObserver = new ResizeObserver(resize);
      resizeObserver.observe(container);

      renderer.domElement.style.touchAction = 'none';
      renderer.domElement.style.cursor = 'grab';
      renderer.domElement.addEventListener('pointerdown', onPointerDown);
      window.addEventListener('pointermove', onPointerMove);
      window.addEventListener('pointerup', onPointerUp);

      handlePulse = () => {
        spinBoost = 0.035; // sudden rotation speed boost on form typing!
      };
      window.addEventListener('globe-pulse', handlePulse);

      const animate = () => {
        frameId = requestAnimationFrame(animate);
        
        if (globeGroup) {
          // Standard auto rotation + dynamic typing spinBoost
          const speed = (autoRotate ? 0.0018 : 0) + spinBoost;
          globeGroup.rotation.y += speed;
          // Slowly decay the spinBoost back to zero
          spinBoost *= 0.94;
        }
        
        if (stars) stars.rotation.y += 0.00005;

        // Animate the active rings (ping sonar wave expansion)
        activeRings.forEach((ring) => {
          ring.scale.x += 0.015;
          ring.scale.y += 0.015;
          if (ring.scale.x > 3.2) {
            ring.scale.x = 1.0;
            ring.scale.y = 1.0;
          }
          // Fade opacity out as scale grows
          ring.material.opacity = Math.max(0, 0.65 * (1 - (ring.scale.x - 1) / 2.2));
        });

        renderer.render(scene, camera);
      };
      animate();
    } catch (err) {
      console.warn('WebGL not supported or blocked, falling back to 2D view:', err);
      setWebGlSupported(false);
      return;
    }

    return () => {
      if (frameId) cancelAnimationFrame(frameId);
      if (idleTimeout) clearTimeout(idleTimeout);
      if (resizeObserver) resizeObserver.disconnect();
      window.removeEventListener('globe-pulse', handlePulse);
      if (renderer && renderer.domElement) {
        renderer.domElement.removeEventListener('pointerdown', onPointerDown);
        window.removeEventListener('pointermove', onPointerMove);
        window.removeEventListener('pointerup', onPointerUp);
        if (container.contains(renderer.domElement)) {
          container.removeChild(renderer.domElement);
        }
        renderer.dispose();
      }
      if (globeGeo) globeGeo.dispose();
      if (globeMat) globeMat.dispose();
      if (texture) texture.dispose();
      if (starMat) starMat.dispose();
      if (starGeo) starGeo.dispose();
      if (stemGeo) stemGeo.dispose();
      if (stemMat) stemMat.dispose();
      if (headGeo) headGeo.dispose();
      if (headMat) headMat.dispose();
      if (ringGeo) ringGeo.dispose();
      if (ringMat) ringMat.dispose();
      
      // Dispose individual ring materials
      activeRings.forEach((ring) => {
        if (ring.material) ring.material.dispose();
      });
    };
  }, []);

  if (!webGlSupported) {
    return (
      <div
        style={{
          width: '100%',
          height: '100%',
          background: 'transparent',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          position: 'relative',
          overflow: 'hidden',
          fontFamily: 'ui-sans-serif, system-ui, sans-serif',
        }}
      >
        <svg
          viewBox="0 0 100 100"
          style={{
            width: '200px',
            height: '200px',
            position: 'relative',
          }}
        >
          <defs>
            <clipPath id="globe-clip">
              <circle cx="50" cy="50" r="46" />
            </clipPath>
          </defs>
          
          {/* Globe base */}
          <circle cx="50" cy="50" r="46" fill="#111111" stroke="rgba(255,255,255,0.15)" strokeWidth="1" />
          
          {/* Star points in the background of fallback */}
          <circle cx="20" cy="15" r="0.5" fill="rgba(255,255,255,0.3)" />
          <circle cx="85" cy="25" r="0.7" fill="rgba(255,255,255,0.4)" />
          <circle cx="75" cy="80" r="0.5" fill="rgba(255,255,255,0.3)" />
          <circle cx="15" cy="70" r="0.6" fill="rgba(255,255,255,0.5)" />

          {/* Rotating continents group */}
          <g clipPath="url(#globe-clip)">
            <g style={{ animation: 'globeRotation 18s linear infinite' }}>
              {/* Copy 1 */}
              <g transform="translate(0, 0)">
                <path d="M20,20 C15,25 12,35 15,45 C18,48 22,50 25,48 C28,45 30,35 28,30 C26,25 22,18 20,20 Z" fill="rgba(255,255,255,0.4)" />
                <path d="M25,48 C28,52 30,60 28,70 C26,78 22,82 20,85 C18,82 17,70 18,60 C19,54 22,50 25,48 Z" fill="rgba(255,255,255,0.4)" />
                <path d="M45,20 C55,18 70,20 80,28 C85,32 82,42 75,45 C68,48 60,40 55,42 C50,44 48,35 45,20 Z" fill="rgba(255,255,255,0.4)" />
                <path d="M48,42 C55,42 58,48 56,58 C54,68 50,75 48,78 C44,75 42,65 44,55 C46,48 47,44 48,42 Z" fill="rgba(255,255,255,0.4)" />
                <path d="M75,60 C80,60 84,64 82,70 C80,74 74,74 72,70 C70,66 72,60 75,60 Z" fill="rgba(255,255,255,0.4)" />
                {/* Pin on India */}
                <circle cx="56" cy="40" r="1.5" fill="#ff3b30" />
                <circle cx="56" cy="40" r="3.2" fill="none" stroke="#ff3b30" strokeWidth="0.5" opacity="0.8" />
              </g>
              {/* Copy 2 (loop) offset by 100 */}
              <g transform="translate(100, 0)">
                <path d="M20,20 C15,25 12,35 15,45 C18,48 22,50 25,48 C28,45 30,35 28,30 C26,25 22,18 20,20 Z" fill="rgba(255,255,255,0.4)" />
                <path d="M25,48 C28,52 30,60 28,70 C26,78 22,82 20,85 C18,82 17,70 18,60 C19,54 22,50 25,48 Z" fill="rgba(255,255,255,0.4)" />
                <path d="M45,20 C55,18 70,20 80,28 C85,32 82,42 75,45 C68,48 60,40 55,42 C50,44 48,35 45,20 Z" fill="rgba(255,255,255,0.4)" />
                <path d="M48,42 C55,42 58,48 56,58 C54,68 50,75 48,78 C44,75 42,65 44,55 C46,48 47,44 48,42 Z" fill="rgba(255,255,255,0.4)" />
                <path d="M75,60 C80,60 84,64 82,70 C80,74 74,74 72,70 C70,66 72,60 75,60 Z" fill="rgba(255,255,255,0.4)" />
                {/* Pin on India */}
                <circle cx="56" cy="40" r="1.5" fill="#ff3b30" />
                <circle cx="56" cy="40" r="3.2" fill="none" stroke="#ff3b30" strokeWidth="0.5" opacity="0.8" />
              </g>
            </g>
          </g>
          
          {/* Wireframe grids for 3D depth */}
          <ellipse cx="50" cy="50" rx="46" ry="12" fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="0.8" />
          <ellipse cx="50" cy="50" rx="18" ry="46" fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="0.8" />
        </svg>
        <style>{`
          @keyframes globeRotation {
            from { transform: translateX(0px); }
            to { transform: translateX(-100px); }
          }
        `}</style>
      </div>
    );
  }

  return (
    <div
      style={{
        width: '100%',
        height: '100%',
        background: 'transparent',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        position: 'relative',
        overflow: 'hidden',
        fontFamily: 'ui-sans-serif, system-ui, sans-serif',
      }}
    >
      <div ref={containerRef} style={{ width: '100%', height: '100%' }} />
    </div>
  );
}